import { mulberry32 } from './proceduralGeneration';
import { simpleHash, hexToRgba } from './starUtils';

// Parse hex color to {r, g, b}
const hexToRgb = (hex) => ({
    r: parseInt(hex.slice(1, 3), 16),
    g: parseInt(hex.slice(3, 5), 16),
    b: parseInt(hex.slice(5, 7), 16),
});

// Lerp between two {r,g,b} objects
const lerpColor = (a, b, t) => ({
    r: Math.round(a.r + (b.r - a.r) * t),
    g: Math.round(a.g + (b.g - a.g) * t),
    b: Math.round(a.b + (b.b - a.b) * t),
});

const WARM = hexToRgb('#ffd7a0');
const COOL = hexToRgb('#4a7fff');

/**
 * Generate deterministic spiral galaxy data for a user.
 * All positions are relative to (0,0) — caller offsets by galaxy center.
 */
export const generateGalaxyData = (userId) => {
    const seed = simpleHash(userId) + 7919;
    const rng = mulberry32(seed);

    const armCount = 2 + Math.floor(rng() * 3); // 2-4
    const rotation = rng() * Math.PI * 2;
    const axialTilt = 0.45 + rng() * 0.3; // 0.45-0.75
    const winding = 2.5 + rng() * 1.5; // 2.5-4.0
    const galaxyRadius = 250 + rng() * 100; // 250-350
    const coreSize = 0.18 + rng() * 0.1; // 0.18-0.28
    const coreRadius = galaxyRadius * coreSize;

    // Pre-compute arm particles
    const particleCount = 300;
    const particles = new Array(particleCount);

    for (let i = 0; i < particleCount; i++) {
        const armIndex = i % armCount;
        const t = rng() * winding;
        const progress = t / winding; // 0 = core, 1 = outer edge

        // Archimedean spiral
        const r = coreRadius + (galaxyRadius - coreRadius) * progress;
        const theta = t + (armIndex / armCount) * Math.PI * 2 + rotation;

        // Scatter perpendicular to arm — wider at outer edges
        const spread = 8 + progress * 35;
        const scatter = (rng() - 0.5) * 2 * spread;
        const tangentAngle = theta + Math.PI / 2;

        const x = r * Math.cos(theta) + scatter * Math.cos(tangentAngle);
        const y = (r * Math.sin(theta) + scatter * Math.sin(tangentAngle)) * axialTilt;

        const dotRadius = 0.6 + rng() * 1.8;
        const alpha = 0.15 + rng() * 0.45;

        particles[i] = { x, y, radius: dotRadius, progress, alpha };
    }

    // Pre-compute arm curve polylines for glow strokes
    const armCurves = [];
    const curveSteps = 40;
    for (let a = 0; a < armCount; a++) {
        const points = new Array(curveSteps);
        for (let s = 0; s < curveSteps; s++) {
            const t = (s / (curveSteps - 1)) * winding;
            const r = coreRadius + (galaxyRadius - coreRadius) * (t / winding);
            const theta = t + (a / armCount) * Math.PI * 2 + rotation;
            points[s] = {
                x: r * Math.cos(theta),
                y: r * Math.sin(theta) * axialTilt,
            };
        }
        armCurves.push(points);
    }

    return { galaxyRadius, coreRadius, axialTilt, particles, armCurves };
};

/**
 * Draw all galaxy visuals + connection lines onto a single canvas context.
 * Each entry in `galaxies` must have: x, y, color, galaxyRadius, coreRadius, particles, armCurves.
 */
export const drawGalaxyVisuals = (ctx, galaxies) => {
    if (!galaxies || galaxies.length === 0) return;

    // --- Draw each galaxy ---
    for (let g = 0; g < galaxies.length; g++) {
        const gal = galaxies[g];
        const { x: cx, y: cy, color, galaxyRadius, coreRadius, particles, armCurves } = gal;
        const accent = hexToRgb(color);

        // 1. Outer halo
        const haloGrad = ctx.createRadialGradient(cx, cy, coreRadius, cx, cy, galaxyRadius * 1.2);
        haloGrad.addColorStop(0, hexToRgba(color, 0.08));
        haloGrad.addColorStop(0.6, hexToRgba(color, 0.03));
        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = haloGrad;
        ctx.beginPath();
        ctx.arc(cx, cy, galaxyRadius * 1.2, 0, Math.PI * 2);
        ctx.fill();

        // 2. Arm particles
        for (let i = 0; i < particles.length; i++) {
            const p = particles[i];
            // Color: inner = warm lerp with accent, outer = cool lerp with accent
            let c;
            if (p.progress < 0.5) {
                const t = p.progress / 0.5;
                c = lerpColor(WARM, accent, t);
            } else {
                const t = (p.progress - 0.5) / 0.5;
                c = lerpColor(accent, COOL, t);
            }
            ctx.fillStyle = `rgba(${c.r},${c.g},${c.b},${p.alpha})`;
            ctx.beginPath();
            ctx.arc(cx + p.x, cy + p.y, p.radius, 0, Math.PI * 2);
            ctx.fill();
        }

        // 3. Arm glow lines
        ctx.strokeStyle = hexToRgba(color, 0.08);
        ctx.lineWidth = 1.5;
        for (let a = 0; a < armCurves.length; a++) {
            const pts = armCurves[a];
            ctx.beginPath();
            ctx.moveTo(cx + pts[0].x, cy + pts[0].y);
            for (let s = 1; s < pts.length; s++) {
                ctx.lineTo(cx + pts[s].x, cy + pts[s].y);
            }
            ctx.stroke();
        }

        // 4. Core glow — multi-stop radial gradient
        const coreGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, coreRadius * 2);
        coreGrad.addColorStop(0, 'rgba(255,255,255,0.9)');
        coreGrad.addColorStop(0.15, 'rgba(255,248,220,0.6)');
        coreGrad.addColorStop(0.5, hexToRgba(color, 0.3));
        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = coreGrad;
        ctx.beginPath();
        ctx.arc(cx, cy, coreRadius * 2, 0, Math.PI * 2);
        ctx.fill();
    }

    // --- Connection lines between nearby galaxies ---
    const MAX_DIST = 5000;
    const MAX_DIST_SQ = MAX_DIST * MAX_DIST;

    for (let i = 0; i < galaxies.length; i++) {
        for (let j = i + 1; j < galaxies.length; j++) {
            const a = galaxies[i];
            const b = galaxies[j];
            const dx = b.x - a.x;
            const dy = b.y - a.y;
            const distSq = dx * dx + dy * dy;
            if (distSq > MAX_DIST_SQ) continue;

            const dist = Math.sqrt(distSq);
            // Fade out as distance approaches max
            const fade = 1 - dist / MAX_DIST;
            const opacity = 0.06 * fade;

            // Midpoint with perpendicular offset for a gentle arc
            const mx = (a.x + b.x) / 2;
            const my = (a.y + b.y) / 2;
            const perpX = -dy / dist * dist * 0.1;
            const perpY = dx / dist * dist * 0.1;

            ctx.strokeStyle = `rgba(255,255,255,${opacity})`;
            ctx.lineWidth = 0.5;
            ctx.beginPath();
            ctx.moveTo(a.x, a.y);
            ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
            ctx.stroke();
        }
    }
};

