// Animated fly-to for smooth camera transitions
const flyAnimRef = useRef(null);

const flyTo = useCallback((targetX, targetY, targetZoom, duration = 600) => {
    if (flyAnimRef.current) cancelAnimationFrame(flyAnimRef.current);

    const startX = camera.x;
    const startY = camera.y;
    const startZoom = zoom;
    const startTime = performance.now();

    const easeOut = (t) => 1 - Math.pow(1 - t, 3); // cubic ease-out

    const animate = (now) => {
        const elapsed = now - startTime;
        const progress = Math.min(elapsed / duration, 1);
        const t = easeOut(progress);

        setCamera({
            x: startX + (targetX - startX) * t,
            y: startY + (targetY - startY) * t,
        });
        setZoom(startZoom + (targetZoom - startZoom) * t);

        if (progress < 1) {
            flyAnimRef.current = requestAnimationFrame(animate);
        } else {
            flyAnimRef.current = null;
        }
    };

    flyAnimRef.current = requestAnimationFrame(animate);
}, [camera, zoom]);

return {
    stageRef,
    stageSize,
    camera,
    zoom,
    isDragging,
    centerWorld,
    getLayerProps,
    getViewportBounds,
    stageEvents,
    flyTo,
};

