import { useState, useRef, useCallback, useMemo, useEffect } from 'react';
import { userHomeCoords, HOME_SCALE, GUEST_SCALE } from '../utils/starUtils';

const useUniverseCamera = (userId, hasOwnPosts) => {
    const stageRef = useRef(null);
    const dragStartRef = useRef(null);
    const lastPinchDist = useRef(null);
    const isPinching = useRef(false);
    const hasAdjustedZoom = useRef(false);

    const [stageSize, setStageSize] = useState({
        width: window.innerWidth,
        height: window.innerHeight,
    });

    const initialCamera = useMemo(() => {
        if (!userId) return { x: 0, y: 0 };
        return userHomeCoords(userId);
    }, [userId]);

    // Start logged-in users at HOME_SCALE; will adjust after first fetch if no posts
    const initialZoom = useMemo(() => (userId ? HOME_SCALE : GUEST_SCALE), [userId]);

    const [camera, setCamera] = useState(initialCamera);
    const [zoom, setZoom] = useState(initialZoom);
    const [isDragging, setIsDragging] = useState(false);

    // If logged-in user has no posts, zoom out so they can see other galaxies
    useEffect(() => {
        if (hasAdjustedZoom.current) return;
        if (hasOwnPosts === null) return; // still loading
        if (!userId) return; // guests already at GUEST_SCALE
        if (!hasOwnPosts) {
            hasAdjustedZoom.current = true;
            setCamera({ x: 0, y: 0 });
            setZoom(GUEST_SCALE);
        } else {
            hasAdjustedZoom.current = true;
        }
    }, [hasOwnPosts, userId]);

    // Resize
    useEffect(() => {
        const onResize = () => setStageSize({ width: window.innerWidth, height: window.innerHeight });
        window.addEventListener('resize', onResize);
        return () => window.removeEventListener('resize', onResize);
    }, []);

    // Center world coords (for display)
    const centerWorld = useMemo(() => ({
        x: Math.round(camera.x),
        y: Math.round(camera.y),
    }), [camera]);

    // Layer transform helper
    const getLayerProps = useCallback((parallaxFactor) => ({
        x: stageSize.width / 2 - camera.x * parallaxFactor * zoom,
        y: stageSize.height / 2 - camera.y * parallaxFactor * zoom,
        scaleX: zoom,
        scaleY: zoom,
    }), [camera, zoom, stageSize]);

    // Viewport bounds at parallax 1.0 (for data fetching)
    const getViewportBounds = useCallback(() => {
        const halfW = (stageSize.width / 2) / zoom;
        const halfH = (stageSize.height / 2) / zoom;
        const pad = 200 / zoom;
        return {
            minX: camera.x - halfW - pad,
            maxX: camera.x + halfW + pad,
            minY: camera.y - halfH - pad,
            maxY: camera.y + halfH + pad,
        };
    }, [camera, zoom, stageSize]);

    // --- Drag handling (Stage is NOT draggable) ---
    const handleMouseDown = useCallback((e) => {
        // Only left button for mouse
        if (e.evt.button !== undefined && e.evt.button !== 0) return;
        dragStartRef.current = {
            pointerX: e.evt.clientX ?? e.evt.touches?.[0]?.clientX,
            pointerY: e.evt.clientY ?? e.evt.touches?.[0]?.clientY,
            camX: camera.x,
            camY: camera.y,
        };
        setIsDragging(true);
    }, [camera]);

    const handleMouseMove = useCallback((e) => {
        if (!dragStartRef.current) return;
        if (isPinching.current) return;
        const px = e.evt.clientX ?? e.evt.touches?.[0]?.clientX;
        const py = e.evt.clientY ?? e.evt.touches?.[0]?.clientY;
        if (px == null || py == null) return;
        const dx = (px - dragStartRef.current.pointerX) / zoom;
        const dy = (py - dragStartRef.current.pointerY) / zoom;
        setCamera({
            x: dragStartRef.current.camX - dx,
            y: dragStartRef.current.camY - dy,
        });
    }, [zoom]);

    const handleMouseUp = useCallback(() => {
        dragStartRef.current = null;
        setIsDragging(false);
        isPinching.current = false;
        lastPinchDist.current = null;
    }, []);

    // --- Wheel zoom ---
    const handleWheel = useCallback((e) => {
        e.evt.preventDefault();
        const stage = stageRef.current;
        if (!stage) return;

        const pointer = stage.getPointerPosition();
        if (!pointer) return;

        const screenCenterX = stageSize.width / 2;
        const screenCenterY = stageSize.height / 2;

        const scaleBy = 1.08;
        const direction = e.evt.deltaY > 0 ? -1 : 1;
        const oldZoom = zoom;
        const newZoom = Math.min(Math.max(
            direction > 0 ? oldZoom * scaleBy : oldZoom / scaleBy,
            0.02
        ), 5);

        // World point under cursor before zoom
        const worldX = camera.x + (pointer.x - screenCenterX) / oldZoom;
        const worldY = camera.y + (pointer.y - screenCenterY) / oldZoom;

        // Adjust camera so same world point stays under cursor
        setCamera({
            x: worldX - (pointer.x - screenCenterX) / newZoom,
            y: worldY - (pointer.y - screenCenterY) / newZoom,
        });
        setZoom(newZoom);
    }, [zoom, camera, stageSize]);

    // --- Touch / Pinch ---
    const handleTouchMove = useCallback((e) => {
        const touch = e.evt;
        if (touch.touches.length === 2) {
            // Pinch zoom
            isPinching.current = true;
            touch.preventDefault();

            const t1 = touch.touches[0];
            const t2 = touch.touches[1];
            const dist = Math.hypot(t2.clientX - t1.clientX, t2.clientY - t1.clientY);

            if (lastPinchDist.current === null) {
                lastPinchDist.current = dist;
                return;
            }

            const oldZoom = zoom;
            const newZoom = Math.min(Math.max(oldZoom * (dist / lastPinchDist.current), 0.02), 5);
            lastPinchDist.current = dist;

            const centerX = (t1.clientX + t2.clientX) / 2;
            const centerY = (t1.clientY + t2.clientY) / 2;
            const screenCenterX = stageSize.width / 2;
            const screenCenterY = stageSize.height / 2;

            const worldX = camera.x + (centerX - screenCenterX) / oldZoom;
            const worldY = camera.y + (centerY - screenCenterY) / oldZoom;

            setCamera({
                x: worldX - (centerX - screenCenterX) / newZoom,
                y: worldY - (centerY - screenCenterY) / newZoom,
            });
            setZoom(newZoom);
        } else if (touch.touches.length === 1 && !isPinching.current) {
            // Single finger drag — handled by mouseMove logic
            handleMouseMove(e);
        }
    }, [zoom, camera, stageSize, handleMouseMove]);

    const handleTouchEnd = useCallback(() => {
        lastPinchDist.current = null;
        if (isPinching.current) {
            isPinching.current = false;
            dragStartRef.current = null;
        }
    }, []);

    const stageEvents = useMemo(() => ({
        onMouseDown: handleMouseDown,
        onMouseMove: handleMouseMove,
        onMouseUp: handleMouseUp,
        onWheel: handleWheel,
        onTouchStart: handleMouseDown,
        onTouchMove: handleTouchMove,
        onTouchEnd: handleTouchEnd,
    }), [handleMouseDown, handleMouseMove, handleMouseUp, handleWheel, handleTouchMove, handleTouchEnd]);

    return {
        stageRef,
        stageSize,
        camera,
        zoom,
        isDragging,
        centerWorld,
        getLayerProps,
        getViewportBounds,
        stageEvents,
    };
};

export default useUniverseCamera;

import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Stage } from 'react-konva';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../Context/useAuth';
import { getUniversePosts, getUserData } from '../../../API/Api';
import useUniverseCamera from './hooks/useUniverseCamera';
import DeepSpaceLayer from './layers/DeepSpaceLayer';
import MidGalaxyLayer from './layers/MidGalaxyLayer';
import InteractiveLayer from './layers/InteractiveLayer';
import { extractSnippet, userHomeCoords } from './utils/starUtils';
import styles from './Universe.module.css';

const Universe = () => {
    const navigate = useNavigate();
    const { user } = useAuth();
    const userId = user?.userData?.[0]?.id || null;

    const debounceRef = useRef(null);
    const [posts, setPosts] = useState(new Map());
    const [selectedPost, setSelectedPost] = useState(null);
    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
    const [galaxyProfile, setGalaxyProfile] = useState(null);
    const [pulsingId, setPulsingId] = useState(null);
    // null = still loading, true/false = resolved
    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);

    const {
        stageRef,
        stageSize,
        camera,
        zoom,
        isDragging,
        centerWorld,
        getLayerProps,
        getViewportBounds,
        stageEvents,
    } = useUniverseCamera(userId, hasOwnPosts);

    // Debounced fetch on camera/zoom change
    useEffect(() => {
        if (debounceRef.current) clearTimeout(debounceRef.current);

        debounceRef.current = setTimeout(async () => {
            const bounds = getViewportBounds();
            try {
                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
                if (result?.data) {
                    setPosts(prev => {
                        const next = new Map(prev);
                        for (const post of result.data) {
                            next.set(post.id, post);
                        }
                        return next;
                    });
                    // Check if any returned posts belong to this user
                    if (userId && hasOwnPosts === null) {
                        const ownsAny = result.data.some(p => p.users?.id === userId);
                        setHasOwnPosts(ownsAny);
                    }
                }
            } catch (err) {
                console.error('Failed to fetch universe posts:', err);
            }
        }, 400);

        return () => {
            if (debounceRef.current) clearTimeout(debounceRef.current);
        };
    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);

    const handleStarClick = useCallback((post) => {
        setSelectedPost(post);
        setSelectedGalaxy(null);
        setGalaxyProfile(null);
        setPulsingId(post.id);
        setTimeout(() => setPulsingId(null), 400);
    }, []);

    const handleGalaxyClick = useCallback(async (galaxy) => {
        setSelectedGalaxy(galaxy);
        setSelectedPost(null);
        setGalaxyProfile(null);
        try {
            const data = await getUserData(galaxy.userId);
            const profile = data?.userData?.[0] || null;
            setGalaxyProfile(profile);
        } catch (err) {
            console.error('Failed to fetch galaxy profile:', err);
        }
    }, []);

    const handleReadPost = useCallback(() => {
        if (!selectedPost) return;
        navigate(`/home/post/${selectedPost.id}`);
    }, [selectedPost, navigate]);

    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
    const showTitles = zoom > 0.5;

    // Derive one label per unique user (galaxy)
    const galaxies = useMemo(() => {
        const seen = new Map();
        for (const post of postArray) {
            const uid = post.users?.id;
            if (!uid || seen.has(uid)) continue;
            const home = userHomeCoords(uid);
            seen.set(uid, {
                userId: uid,
                name: post.users?.name || 'Anonymous',
                x: home.x,
                y: home.y,
            });
        }
        return Array.from(seen.values());
    }, [postArray]);

    return (
        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
            <button className={styles.backButton} onClick={() => navigate('/home')}>
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
                </svg>
                Back
            </button>

            <div className={styles.coordsLabel}>
                {centerWorld.x}, {centerWorld.y}
            </div>

            <Stage
                ref={stageRef}
                width={stageSize.width}
                height={stageSize.height}
                {...stageEvents}
            >
                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
                <InteractiveLayer
                    layerProps={getLayerProps(1.0)}
                    posts={postArray}
                    galaxies={galaxies}
                    zoom={zoom}
                    showTitles={showTitles}
                    pulsingId={pulsingId}
                    onStarClick={handleStarClick}
                    onGalaxyClick={handleGalaxyClick}
                />
            </Stage>

            {selectedGalaxy && galaxyProfile && (
                <div className={styles.galaxyPreviewPanel}>
                    <button
                        className={styles.galaxyPreviewClose}
                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
                    >
                        &times;
                    </button>
                    <div
                        className={styles.galaxyPreviewBg}
                        style={galaxyProfile.background || {}}
                    />
                    <div className={styles.galaxyPreviewContent}>
                        <img
                            className={styles.galaxyPreviewAvatar}
                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
                            alt=""
                        />
                        <div className={styles.galaxyPreviewHeading}>
                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
                        </div>
                        {galaxyProfile.bio && (
                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
                        )}
                        <button
                            className={styles.galaxyPreviewVisitBtn}
                            onClick={() => navigate(`/visit/${selectedGalaxy.userId}`)}
                        >
                            Visit Profile
                        </button>
                    </div>
                </div>
            )}

            {selectedPost && (
                <div className={styles.previewPanel}>
                    <button
                        className={styles.previewClose}
                        onClick={() => setSelectedPost(null)}
                    >
                        &times;
                    </button>
                    <div className={styles.previewAuthor}>
                        <img
                            className={styles.previewAvatar}
                            src={selectedPost.users?.image_url || '/assets/profile.jpg'}
                            alt=""
                        />
                        <span className={styles.previewAuthorName}>
                            {selectedPost.users?.name || 'Anonymous'}
                        </span>
                    </div>
                    <div className={styles.previewTitle}>{selectedPost.title}</div>
                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
                    <div className={styles.previewLikes}>
                        {Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count
                            ? `${selectedPost.likes[0].count} like${selectedPost.likes[0].count !== 1 ? 's' : ''}`
                            : '0 likes'}
                    </div>
                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
                        Read
                    </button>
                </div>
            )}
        </div>
    );
};

export default Universe;

